+NEXT_VERSION="$(printf '%s\n' "$REGISTRY_INFO" | sed -n '2p')"
+PREVIOUS_VERSION="$(printf '%s\n' "$REGISTRY_INFO" | sed -n '3p')"

 echo "latest=$LATEST_VERSION next=$NEXT_VERSION previous=$PREVIOUS_VERSION"

